+        ciArrayKlass* array_klass = ciArrayKlass::make(t, null_free, atomic, true);
+        assert(array_klass->is_elem_null_free() == null_free, "inconsistency");
+
+        // TOOD 8350865 ZGC needs card marks on initializing oop stores
