+  assert(ary_t->klass_is_exact() && ary_t->is_flat(), "must be an exact flat array");
+  assert(ary_t->field_offset().get() != Type::OffsetBot, "unknown offset");
+  if (init_value->is_EncodeP()) {
+    init_value = init_value->in(1);
