+  if (base_uncasted->is_Proj()) {
+    Node* multi = base_uncasted->in(0);
+    if (multi->is_top()) {
+      // The pointer dies, make the memory die, too
+      return multi;
+    } else if (multi->is_Allocate()) {
+      base_local = base_uncasted->as_Proj();
